curl http://localhost:11434/api/generate
```

## 2. Integrate Ollama with SwiftUI

You'll interact with Ollama from Swift using the `URLSession` API.

### a) Create a Swift Model for Ollama

You'll send HTTP requests to the Ollama API endpoint (default: `http://localhost:11434/api/generate`).

#### Example Swift Struct for Ollama Request

```swift
import Foundation

struct OllamaGenerationRequest: Codable {
    let prompt: String
    let parameters: [String: Any]? // e.g., "max_tokens": 100
}

extension OllamaGenerationRequest: JSONable {
    func encode(to encoder: JSONEncoder) throws {
        try encoder.encode(self)
    }
    required init?(from decoder: JSONDecoder?) { throw NSError() } // Not used
}

// Helper to send POST request
func askOllama(prompt: String, parameters: [String: Any]?, completion: @escaping (String) -> Void) {
    let url = URL(string: "http://localhost:11434/api/generate")!
    let task = URLSession.shared.dataTask(with: {
        data, response, error in
        guard let data = data else { completion("Error: No data"); return }
        do {
            let decoder = JSONDecoder()
            let response = try decoder.decode(OllamaGenerationRequest.self, from: data)
            let answer = response.promptResponse // depends on Ollama's output format
            completion(answer)
        } catch {
            completion("Error: \(error.localizedDescription)")
        }
    })
    task.resume(with: URLRequest(url: url))
}
```

**Note:** The response format from Ollama depends on the backend. For Llama models, the output is a JSON object with a `promptResponse` field (text answer). Check [Ollama's API docs](https://ollama.com/docs/api) for the actual structure for your model.

