    fn add(&self, other: &Self) -> Self { // Ограничение: само определение несовместимо, но для примера:
        // Просто вернём self (не реально правильно, для иллюстрации)
        // Настоящая реализация — потребует общего trait bound или отдельного trait для чисел/факториалов.
        Self { n: self.n + other.n } // Не смысловой операцией, но для примера
    }

    fn multiply(&self, other: &Self) -> Self {
        Self { n: self.n * other.n } // Тоже не смыслово, но демонстрирует схему
    }
}

// Но для правильного использования требуется trait bound:
// fn foo<T: NumOp>(...) { ... } — и тогда можно вызывать add/multiply для любого T.
```

#### Важно
